    rawSafety as AnyRow[],
    rawInvoices as AnyRow[],
    rawRFIs as AnyRow[],
    rawChangeOrders as AnyRow[],
    rawDailyReports as AnyRow[],
    rawTeam as AnyRow[],
    rawSubcontractors as AnyRow[]
