          <span style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--slate-400)', textTransform: 'uppercase' }}>Severity:</span>
          {(['all', 'critical', 'high', 'medium', 'low', 'info'] as const).map(sev => (
            <button
              key={sev}
              onClick={() => setFilter(sev)}
