                  borderRadius: '8px',
                  background: 'var(--slate-800)',
                  border: '1px solid var(--slate-700)',
                  color: 'var(--slate-300)',
                  cursor: 'pointer',
                  fontFamily: 'var(--font-body)',
                  fontSize: '13px',
                  fontWeight: 600,
                }}
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

